    <!-- Kanban Columns -->
    <div class="board">
        @for (var i = 0; i < Columns.Length; i++)
        {
            var colIndex = i;
            var column = Columns[colIndex];
            var tasks = FilteredTasksForColumn(column);

            <div class="board-column">
                <div class="column-header">
                    <h3>@column</h3>
                    <span class="badge">@tasks.Count</span>
                </div>

                <div class="column-body">
                    @foreach (var task in tasks)
                    {
                        <div class="task-card">
                            <div class="task-title">@task.Title</div>
                            <div class="task-assignee">@task.Assignee</div>
                            <span class="priority-badge priority-@task.Priority.ToLowerInvariant()">@task.Priority</span>
                            <div class="task-due">@task.DueDate.ToString("MMM dd")</div>

                            <div class="task-actions">
                                @if (colIndex > 0)
                                {
                                    var prevStatus = Columns[colIndex - 1];
                                    <button class="btn btn-sm btn-move" @onclick="() => MoveTaskAsync(task.Id, prevStatus)">← Move Left</button>
                                }
                                @if (colIndex < Columns.Length - 1)
                                {
                                    var nextStatus = Columns[colIndex + 1];
                                    <button class="btn btn-sm btn-move" @onclick="() => MoveTaskAsync(task.Id, nextStatus)">Move Right →</button>
                                }
                            </div>
                        </div>
                    }
                </div>

                @if (_addingToColumn == column)
                {
                    <div class="add-task-form">
                        <input type="text" placeholder="Title" @bind="_newTitle" class="form-input" />
                        <input type="text" placeholder="Assignee" @bind="_newAssignee" class="form-input" />
                        <select @bind="_newPriority" class="form-input">
                            <option value="High">High</option>
                            <option value="Medium">Medium</option>
                            <option value="Low">Low</option>
                        </select>
                        <input type="date" @bind="_newDueDate" class="form-input" />
                        <div class="form-actions">
                            <button class="btn btn-save" @onclick="() => SaveTaskAsync(column)">Save</button>
                            <button class="btn btn-cancel" @onclick="CancelAdd">Cancel</button>
                        </div>
                    </div>
                }
                else
                {
                    <button class="btn btn-add" @onclick="() => StartAdd(column)">+ Add Task</button>
                }
            </div>
        }
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchText = string.Empty;

    // Add-task form state
    private string? _addingToColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> TasksForColumn(string status) =>
        _allTasks.Where(t => t.Status == status).ToList();

    private List<TaskItem> FilteredTasksForColumn(string status) =>
        _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchText) ||
                         t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var old = _allTasks.First(t => t.Id == taskId);
            _allTasks[_allTasks.IndexOf(old)] = old with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private void StartAdd(string column)
    {
        _addingToColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingToColumn = null;

    private async Task SaveTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTitle))
            return;

        try
        {
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);

            // CreateTaskAsync may default to "To Do"; move if the target column differs.
            if (created.Status != column)
            {
                await TaskService.UpdateTaskStatusAsync(created.Id, column);
                created = created with { Status = column };
            }

            _allTasks.Add(created);
            _addingToColumn = null;
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }
}

