/* ── Stats bar ──────────────────────────────────── */
.stats-bar {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: var(--bg-subtle, #f6f8fa);
    border: 1px solid var(--border-default, #d0d7de);
    border-radius: 6px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    font-size: 0.9rem;
}

.stat-overdue strong {
    color: #cf222e;
}

/* ── Search bar ─────────────────────────────────── */
.search-bar {
    margin-bottom: 1rem;
}

.search-input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #d0d7de;
    border-radius: 6px;
    font-size: 0.95rem;
}

/* ── Board layout ───────────────────────────────── */
.board {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-column {
    flex: 1;
    min-width: 250px;
    background: #f6f8fa;
    border: 1px solid #d0d7de;
    border-radius: 8px;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
}

.column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

.column-header h3 {
    margin: 0;
    font-size: 1rem;
}

.column-header .badge {
    background: #656d76;
    color: #fff;
    border-radius: 10px;
    padding: 0.15rem 0.55rem;
    font-size: 0.8rem;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

/* ── Task card ──────────────────────────────────── */
.task-card {
    background: #fff;
    border: 1px solid #d8dee4;
    border-radius: 6px;
    padding: 0.75rem;
}

.task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

.task-assignee {
    font-size: 0.85rem;
    color: #656d76;
    margin-bottom: 0.35rem;
}

.task-due {
    font-size: 0.8rem;
    color: #656d76;
    margin-top: 0.35rem;
}

/* ── Priority badges ────────────────────────────── */
.priority-badge {
    display: inline-block;
    padding: 0.1rem 0.5rem;
    border-radius: 10px;
    font-size: 0.75rem;
    font-weight: 600;
}

.priority-high {
    background: #cf222e;
    color: #fff;
}

.priority-medium {
    background: #bf8700;
    color: #fff;
}

.priority-low {
    background: #1a7f37;
    color: #fff;
}

/* ── Buttons ────────────────────────────────────── */
.task-actions {
    display: flex;
    gap: 0.4rem;
    margin-top: 0.5rem;
}

.btn {
    cursor: pointer;
    border: none;
    border-radius: 4px;
    padding: 0.3rem 0.6rem;
    font-size: 0.8rem;
}

.btn-sm {
    font-size: 0.75rem;
}

.btn-move {
    background: #e8e8e8;
    color: #24292f;
}

.btn-move:hover {
    background: #d0d7de;
}

.btn-add {
    width: 100%;
    margin-top: 0.5rem;
    background: transparent;
    border: 1px dashed #656d76;
    color: #656d76;
    padding: 0.5rem;
}

.btn-add:hover {
    background: #eaeef2;
}

.btn-save {
    background: #2da44e;
    color: #fff;
}

.btn-save:hover {
    background: #1a7f37;
}

.btn-cancel {
    background: #e8e8e8;
    color: #24292f;
}

.btn-cancel:hover {
    background: #d0d7de;
}

/* ── Inline add-task form ───────────────────────── */
.add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    margin-top: 0.5rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px solid #d8dee4;
    border-radius: 6px;
}

.form-input {
    padding: 0.4rem 0.5rem;
    border: 1px solid #d0d7de;
    border-radius: 4px;
    font-size: 0.85rem;
}

.form-actions {
    display: flex;
    gap: 0.4rem;
}

/* ── Stats bar ──────────────────────────────────── */
.stats-bar {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: var(--bg-subtle, #f6f8fa);
    border: 1px solid var(--border-default, #d0d7de);
    border-radius: 6px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    font-size: 0.9rem;
}

.stat-overdue strong {
    color: #cf222e;
}

/* ── Search bar ─────────────────────────────────── */
.search-bar {
    margin-bottom: 1rem;
}

.search-input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #d0d7de;
    border-radius: 6px;
    font-size: 0.95rem;
}

/* ── Board layout ───────────────────────────────── */
.board {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
